"use client";

/**
 * Magic-link sign-in page.
 *
 * Posts the email to magellan-api (`POST /api/v1/auth/magic-link`),
 * which calls Supabase server-side and triggers the email. The link in
 * the email lands back on /auth/callback, which exchanges the code for
 * a session and redirects to `next` (defaults to /data).
 */

import { Suspense, useState, type FormEvent } from "react";
import { useSearchParams } from "next/navigation";

type Status = "idle" | "sending" | "sent" | "error";

/**
 * `useSearchParams` opts the page out of static prerendering unless
 * its caller is inside a Suspense boundary. The inner form reads
 * `?next=`; the boundary lets `next build` prerender the shell.
 */
export default function SignInPage() {
  return (
    <Suspense fallback={null}>
      <SignInForm />
    </Suspense>
  );
}

function SignInForm() {
  const params = useSearchParams();
  const next = params.get("next") ?? "/data";

  const [email, setEmail] = useState("");
  const [status, setStatus] = useState<Status>("idle");
  const [error, setError] = useState<string | null>(null);

  const onSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setStatus("sending");
    setError(null);

    const apiBase = process.env.NEXT_PUBLIC_MAGELLAN_API_BASE_URL;
    try {
      const res = await fetch(`${apiBase}/api/v1/auth/magic-link`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ email, next }),
      });
      if (!res.ok) {
        // API returns the CF error envelope: { ok: false, error: { code, message }, request_id }
        const body = (await res.json().catch(() => null)) as
          | { error?: { message?: string; code?: string } }
          | null;
        setStatus("error");
        setError(body?.error?.message ?? `Sign-in failed (${res.status})`);
        return;
      }
      setStatus("sent");
    } catch (err) {
      setStatus("error");
      setError(err instanceof Error ? err.message : "Network error");
    }
  };

  return (
    <div
      style={{
        flex: 1,
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
        fontFamily: "var(--font-inter), sans-serif",
      }}
    >
      <div style={{ width: "100%", maxWidth: 380 }}>
        <h1
          style={{
            fontFamily: "var(--font-fraunces), serif",
            fontWeight: 300,
            fontSize: 32,
            margin: 0,
            marginBottom: 8,
            letterSpacing: "-0.01em",
          }}
        >
          Sign in to Magellan
        </h1>
        <p style={{ color: "#8a8d94", fontSize: 14, marginTop: 0, marginBottom: 24 }}>
          We&apos;ll email you a one-time link.
        </p>

        {status === "sent" ? (
          <div
            style={{
              padding: 16,
              border: "1px solid #e5e7eb",
              borderRadius: 6,
              background: "#f9fafb",
              fontSize: 14,
              lineHeight: 1.5,
            }}
          >
            Check <b>{email}</b> for a sign-in link. You can close this tab.
          </div>
        ) : (
          <form onSubmit={onSubmit} style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            <label htmlFor="email" style={{ fontSize: 12, color: "#5a5d64", letterSpacing: "0.04em" }}>
              EMAIL
            </label>
            <input
              id="email"
              type="email"
              required
              autoFocus
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="you@example.com"
              disabled={status === "sending"}
              style={{
                padding: "10px 12px",
                border: "1px solid #d1d5db",
                borderRadius: 6,
                fontSize: 15,
                fontFamily: "inherit",
                outline: "none",
              }}
            />
            <button
              type="submit"
              disabled={status === "sending" || !email}
              style={{
                padding: "10px 14px",
                background: "#2a4070",
                color: "#fff",
                border: 0,
                borderRadius: 6,
                fontSize: 14,
                fontWeight: 500,
                cursor: status === "sending" ? "default" : "pointer",
                opacity: status === "sending" || !email ? 0.6 : 1,
              }}
            >
              {status === "sending" ? "Sending..." : "Send magic link"}
            </button>
            {status === "error" && error && (
              <div style={{ color: "#b00020", fontSize: 13 }}>{error}</div>
            )}
          </form>
        )}
      </div>
    </div>
  );
}
